     1→/**
     2→ * GitHub Dark-inspired CSS for the report website.
     3→ * Self-contained — no external CDN dependencies.
     4→ * Supports dark (default) and light themes, sidebar navigation, responsive layout.
     5→ */
     6→
     7→export const REPORT_CSS = `
     8→:root {
     9→  --bg: #0d1117;
    10→  --bg-secondary: #161b22;
    11→  --bg-card: #21262d;
    12→  --border: #30363d;
    13→  --text: #e6edf3;
    14→  --text-muted: #8b949e;
    15→  --accent: #58a6ff;
    16→  --accent-hover: #79b8ff;
    17→  --green-0: #161b22;
    18→  --green-1: #0e4429;
    19→  --green-2: #006d32;
    20→  --green-3: #26a641;
    21→  --green-4: #39d353;
    22→  --user-bg: #1c2d3e;
    23→  --user-border: #388bfd44;
    24→  --assistant-bg: #1c1c1c;
    25→  --assistant-border: #30363d;
    26→  --code-bg: #161b22;
    27→  --badge-codex: #1f6feb;
    28→  --badge-claude: #6e40c9;
    29→  --badge-gemini: #1a7f37;
    30→  --danger: #f85149;
    31→  --warning: #d29922;
    32→  --success: #3fb950;
    33→  --mark-bg: #3d3000;
    34→  --sidebar-width: 240px;
    35→  --font-mono: 'SF Mono', 'Consolas', 'Liberation Mono', 'Menlo', monospace;
    36→}
    37→
    38→[data-theme="light"] {
    39→  --bg: #ffffff;
    40→  --bg-secondary: #f6f8fa;
    41→  --bg-card: #ffffff;
    42→  --border: #d0d7de;
    43→  --text: #1f2328;
    44→  --text-muted: #636c76;
    45→  --accent: #0969da;
    46→  --accent-hover: #0550ae;
    47→  --user-bg: #ddf4ff;
    48→  --user-border: #54aeff44;
    49→  --assistant-bg: #f6f8fa;
    50→  --assistant-border: #d0d7de;
    51→  --code-bg: #f6f8fa;
    52→  --mark-bg: #fff8c5;
    53→  --green-0: #f6f8fa;
    54→  --green-1: #acf2bd;
    55→  --green-2: #40c463;
    56→  --green-3: #30a14e;
    57→  --green-4: #216e39;
    58→}
    59→
    60→*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    61→
    62→html { font-size: 16px; scroll-behavior: smooth; }
    63→
    64→body {
    65→  background: var(--bg);
    66→  color: var(--text);
    67→  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
    68→  line-height: 1.6;
    69→  min-height: 100vh;
    70→  display: flex;
    71→  flex-direction: column;
    72→}
    73→
    74→a { color: var(--accent); text-decoration: none; }
    75→a:hover { color: var(--accent-hover); text-decoration: underline; }
    76→
    77→code {
    78→  font-family: var(--font-mono);
    79→  font-size: 0.875em;
    80→  background: var(--code-bg);
    81→  padding: 0.15em 0.4em;
    82→  border-radius: 4px;
    83→  border: 1px solid var(--border);
    84→}
    85→
    86→pre {
    87→  background: var(--code-bg);
    88→  border: 1px solid var(--border);
    89→  border-radius: 8px;
    90→  padding: 1rem;
    91→  overflow-x: auto;
    92→  margin: 0.75rem 0;
    93→}
    94→
    95→pre code {
    96→  background: none;
    97→  border: none;
    98→  padding: 0;
    99→  font-size: 0.875rem;
   100→}
   101→
   102→h1, h2, h3, h4, h5, h6 {
   103→  color: var(--text);
   104→  line-height: 1.3;
   105→  margin-bottom: 0.5rem;
   106→}
   107→
   108→h1 { font-size: 1.75rem; }
   109→h2 { font-size: 1.375rem; border-bottom: 1px solid var(--border); padding-bottom: 0.4rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }
   110→h3 { font-size: 1.125rem; }
   111→
   112→p { margin-bottom: 0.75rem; }
   113→
   114→ul, ol { padding-left: 1.5rem; margin-bottom: 0.75rem; }
   115→li { margin-bottom: 0.25rem; }
   116→
   117→table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
   118→th, td { padding: 0.5rem 0.75rem; text-align: left; border-bottom: 1px solid var(--border); }
   119→th { color: var(--text-muted); font-weight: 600; font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.05em; background: var(--bg-secondary); }
   120→tr:hover td { background: var(--bg-secondary); }
   121→
   122→/* ── Mobile topbar ── */
   123→.topbar {
   124→  display: none;
   125→  background: var(--bg-secondary);
   126→  border-bottom: 1px solid var(--border);
   127→  padding: 0 1rem;
   128→  align-items: center;
   129→  gap: 0.75rem;
   130→  height: 48px;
   131→  position: sticky;
   132→  top: 0;
   133→  z-index: 200;
   134→}
   135→
   136→.topbar-brand {
   137→  font-weight: 700;
   138→  font-size: 0.95rem;
   139→  color: var(--text);
   140→  flex: 1;
   141→}
   142→
   143→.topbar-actions {
   144→  display: flex;
   145→  align-items: center;
   146→  gap: 0.5rem;
   147→}
   148→
   149→.hamburger, .theme-toggle-btn {
   150→  background: none;
   151→  border: 1px solid var(--border);
   152→  color: var(--text);
   153→  border-radius: 6px;
   154→  padding: 0.3rem 0.5rem;
   155→  cursor: pointer;
   156→  font-size: 1rem;
   157→  line-height: 1;
   158→  display: flex;
   159→  align-items: center;
