   162→
   163→.hamburger:hover, .theme-toggle-btn:hover {
   164→  background: var(--bg-card);
   165→}
   166→
   167→/* ── Sidebar ── */
   168→.sidebar {
   169→  width: var(--sidebar-width);
   170→  background: var(--bg-secondary);
   171→  border-right: 1px solid var(--border);
   172→  position: fixed;
   173→  top: 0;
   174→  left: 0;
   175→  bottom: 0;
   176→  overflow-y: auto;
   177→  z-index: 150;
   178→  display: flex;
   179→  flex-direction: column;
