   185→  border-bottom: 1px solid var(--border);
   186→  display: flex;
   187→  align-items: center;
   188→  justify-content: space-between;
   189→  flex-shrink: 0;
   190→}
   191→
   192→.sidebar-brand {
   193→  font-weight: 700;
   194→  font-size: 1rem;
   195→  color: var(--text);
   196→}
   197→
   198→.sidebar-nav {
   199→  flex: 1;
   200→  padding: 0.5rem 0;
   201→  overflow-y: auto;
   202→}
   203→
   204→.nav-section-label {
