   206→  font-size: 0.7rem;
   207→  font-weight: 600;
   208→  text-transform: uppercase;
   209→  letter-spacing: 0.08em;
   210→  color: var(--text-muted);
   211→}
   212→
   213→.nav-link {
   214→  display: flex;
   215→  align-items: center;
   216→  gap: 0.5rem;
   217→  padding: 0.45rem 1.25rem;
   218→  color: var(--text-muted);
   219→  font-size: 0.9rem;
