   221→  border-radius: 0;
   222→}
   223→
   224→.nav-link:hover {
   225→  color: var(--text);
   226→  background: var(--bg-card);
   227→  text-decoration: none;
   228→}
   229→
   230→.nav-link.active {
   231→  color: var(--accent);
   232→  background: var(--bg-card);
