     1→/**
     2→ * Full-text search: pre-built JSON index embedded as inline JS.
     3→ * Vanilla JS substring search, no external library.
     4→ */
     5→
     6→import type { ManifestEntry } from '../../types/transcript.js'
     7→import type { SearchIndexEntry } from '../../types/report.js'
     8→import type { Translations } from '../i18n/types.js'
     9→import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot } from './layout.js'
    10→
    11→const MAX_INDEX_BYTES = 50_000
    12→const SNIPPET_LEN = 200
    13→
    14→// ---------------------------------------------------------------------------
    15→// Index construction
    16→// ---------------------------------------------------------------------------
    17→
    18→export function buildSearchIndex(
    19→  manifests: ManifestEntry[],
    20→  getSnippet: (m: ManifestEntry) => string,
    21→): SearchIndexEntry[] {
    22→  const entries: SearchIndexEntry[] = []
    23→  let totalBytes = 0
    24→
    25→  for (const m of manifests) {
    26→    let snippet = getSnippet(m).slice(0, SNIPPET_LEN)
    27→    const project = m.project || lastPathSegment(m.cwd) || 'unknown'
    28→    const entry: SearchIndexEntry = {
    29→      url: transcriptUrl(m),
    30→      title: m.title || m.session_id,
    31→      client: m.client,
    32→      project,
    33→      date: m.started_at.slice(0, 10),
    34→      snippet,
    35→    }
    36→    const entryBytes = JSON.stringify(entry).length
    37→    if (totalBytes + entryBytes > MAX_INDEX_BYTES) {
    38→      // Truncate snippet to fit within budget
    39→      const remaining = MAX_INDEX_BYTES - totalBytes - (entryBytes - snippet.length) - 10
    40→      if (remaining < 20) break
    41→      snippet = snippet.slice(0, remaining)
    42→      entry.snippet = snippet
    43→    }
    44→    totalBytes += JSON.stringify(entry).length
    45→    entries.push(entry)
    46→  }
    47→
    48→  return entries
    49→}
    50→
    51→function transcriptUrl(m: ManifestEntry): string {
    52→  return transcriptUrlFromRoot(m)
    53→}
    54→
    55→function lastPathSegment(p: string): string {
    56→  return p.split(/[/\\]/).filter(Boolean).at(-1) ?? ''
    57→}
    58→
    59→// ---------------------------------------------------------------------------
    60→// Search page renderer
    61→// ---------------------------------------------------------------------------
    62→
    63→export function renderSearchPage(index: SearchIndexEntry[], t?: Translations): string {
    64→  // Escape </script> to prevent script-injection via manifest-controlled content
    65→  const indexJson = JSON.stringify(index).replace(/<\//g, '<\\/')
    66→  const nav = renderNav('search', 0, t)
    67→  const title = t?.search.title ?? 'Search'
    68→  const placeholder = t?.search.placeholder ?? 'Search sessions, messages, and content...'
    69→
    70→  // Build unique client and project lists for filter dropdowns
    71→  const clients = [...new Set(index.map(e => e.client).filter(Boolean))].sort()
    72→  const projects = [...new Set(index.map(e => e.project).filter(Boolean))].sort()
    73→
    74→  const clientOptions = clients
    75→    .map(c => `<option value="${escHtml(c)}">${escHtml(c)}</option>`)
    76→    .join('')
    77→  const projectOptions = projects
    78→    .map(p => `<option value="${escHtml(p)}">${escHtml(p)}</option>`)
    79→    .join('')
    80→
    81→  const extraHead = `<script>
    82→const SEARCH_INDEX = ${indexJson};
    83→</script>`
    84→
    85→  const content = `
    86→<div class="page-header">
    87→  <h1>${escHtml(title)}</h1>
    88→  <p class="subtitle">Full-text search across all imported sessions</p>
    89→</div>
    90→
    91→<div style="display:flex;gap:0.5rem;margin-bottom:0.75rem;flex-wrap:wrap">
    92→  <select id="filter-client" class="search-filter-select">
    93→    <option value="">All Clients</option>
    94→    ${clientOptions}
    95→  </select>
    96→  <select id="filter-project" class="search-filter-select">
    97→    <option value="">All Projects</option>
    98→    ${projectOptions}
    99→  </select>
   100→</div>
   101→<input
   102→  type="search"
   103→  id="search-input"
   104→  class="search-box"
   105→  placeholder="${escHtml(placeholder)}"
   106→  autofocus
   107→>
   108→<div id="search-count"></div>
   109→<div id="search-results" class="search-results"></div>
   110→
   111→<script>
   112→(function() {
   113→  var input = document.getElementById('search-input');
   114→  var resultsEl = document.getElementById('search-results');
   115→  var countEl = document.getElementById('search-count');
   116→  var clientSel = document.getElementById('filter-client');
   117→  var projectSel = document.getElementById('filter-project');
   118→
   119→  function highlight(text, query) {
   120→    if (!query) return escHtml(text);
   121→    var escaped = escHtml(text);
   122→    var escapedQ = escHtml(query);
   123→    var lower = escaped.toLowerCase();
   124→    var lowerQ = escapedQ.toLowerCase();
   125→    if (!lowerQ) return escaped;
   126→    var result = '';
   127→    var i = 0;
   128→    while (i < escaped.length) {
   129→      var idx = lower.indexOf(lowerQ, i);
   130→      if (idx === -1) { result += escaped.slice(i); break; }
   131→      result += escaped.slice(i, idx) + '<mark>' + escaped.slice(idx, idx + lowerQ.length) + '</mark>';
   132→      i = idx + lowerQ.length;
   133→    }
   134→    return result;
   135→  }
   136→
   137→  function escHtml(s) {
   138→    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
   139→  }
   140→
   141→  function renderResults() {
   142→    var query = (input.value || '');
   143→    var q = query.toLowerCase().trim();
   144→    var filterClient = clientSel ? clientSel.value : '';
   145→    var filterProject = projectSel ? projectSel.value : '';
   146→    var filtered = SEARCH_INDEX.filter(function(e) {
   147→      if (filterClient && e.client !== filterClient) return false;
   148→      if (filterProject && e.project !== filterProject) return false;
   149→      if (!q) return true;
   150→      return (e.title || '').toLowerCase().includes(q) ||
   151→             (e.snippet || '').toLowerCase().includes(q);
   152→    });
   153→    if (!q && !filterClient && !filterProject) {
   154→      resultsEl.innerHTML = '';
   155→      countEl.textContent = SEARCH_INDEX.length + ' session(s) indexed';
   156→      return;
   157→    }
   158→    countEl.textContent = filtered.length + ' result(s)' + (q ? ' for "' + escHtml(q) + '"' : '');
   159→    resultsEl.innerHTML = filtered.map(function(e) {
   160→      return '<div class="search-result">' +
   161→        '<div class="search-result-title"><a href="' + escHtml(e.url) + '">' + highlight(e.title, query) + '</a></div>' +
   162→        '<div class="search-result-meta"><span class="badge badge-' + escHtml(e.client) + '">' + escHtml(e.client) + '</span> &nbsp; ' + escHtml(e.date) + '</div>' +
   163→        '<div class="search-result-snippet">' + highlight(e.snippet, query) + '</div>' +
   164→        '</div>';
   165→    }).join('');
   166→  }
   167→
   168→  renderResults();
   169→  input.addEventListener('input', renderResults);
   170→  if (clientSel) clientSel.addEventListener('change', renderResults);
   171→  if (projectSel) projectSel.addEventListener('change', renderResults);
   172→})();
   173→</script>`
   174→
   175→  return htmlShell(title, content, nav, extraHead)
   176→}
